    var getCodeBtnWidth = 90 * scaleRatio; // 获取验证码按钮宽度

    var btnHeight = 45 * scaleRatio; // 统一按钮高度

    console.log("布局参数: scaleRatio=" + scaleRatio.toFixed(2)); // ==================== 手机号输入行 ====================
    // 布局：[图标] [输入框] 整体居中

    var phoneRowWidth = iconSize + 15 + inputWidth; // 总宽度

